/**
 * Megastructure System — AST-30 (enhanced)
 *
 * Endgame construction projects: Orbital Platform (3 stages) and Dyson Swarm (8 stages).
 * Each stage requires massive resource investment, Engineer robots, and time.
 *
 * Dyson Swarm enhancements:
 * - 8 stages (up from 5) with escalating costs and complexity
 * - Active resource drain: select stages consume resources per drain interval while under
 *   construction. If resources run dry, construction stalls — forcing supply-chain rethinks.
 * - Construction crises: random events that pause construction mid-build, requiring
 *   either a resource payment (resolve) or a progress sacrifice (skip).
 */

// ── Crisis definitions ────────────────────────────────────────────────────────

export interface CrisisDef {
  id: string;
  name: string;
  description: string;
  /** Resources required to resolve the crisis and resume construction */
  resolutionCost: Partial<Record<string, number>>;
  /** Fraction of stage progress lost when skipping the crisis (0–1) */
  progressPenalty: number;
  /**
   * Ticks of mandatory repair downtime after paying the resolution cost.
   * Construction stalls during this window. If undefined, crisis clears immediately on payment.
   */
  pauseWindowTicks?: number;
}

