export interface MegastructureBonus {
  type:
    | 'robot_cap'
    | 'energy_unlimited'
    | 'sensor_range'
    | 'win_condition'
    | 'habitat_ready';
  value: number;
  description: string;
}

export interface MegastructureStageDef {
  index: number;
  name: string;
  description: string;
  /** Refined material costs deducted when stage begins */
  cost: Partial<Record<string, number>>;
  /** Minimum Engineer robots needed; construction stalls at 0 */
  engineersRequired: number;
  /** Ticks to complete with exactly engineersRequired engineers */
  baseTicks: number;
  bonus: MegastructureBonus;
  /**
   * Resources consumed from refinedStorage every drainIntervalTicks while this stage is active.
   * If the storage can't cover the drain, construction stalls until resources recover.
   */
  activeDrain?: Partial<Record<string, number>>;
  /** How often (in ticks) the active drain fires. Default: 3600 */
  drainIntervalTicks?: number;
  /**
   * Crisis type that can randomly fire during this stage.
   * Crisis fires at most once per stage per activation.
   */
  crisisType?: string;
  /** Per-tick probability of a crisis firing (if crisisType is set). Default: 0.00003 */
  crisisProbability?: number;
}

export interface MegastructureDef {
  id: MegastructureId;
  name: string;
  description: string;
  stages: MegastructureStageDef[];
  /** Require another megastructure at a minimum stage count */
  prerequisite?: { id: MegastructureId; minCompletedStages: number };
  /** Per-stage tech prerequisites — stage index to tech node ID(s) */
  stageTechGates?: Record<number, string[]>;
}

