// ── State ─────────────────────────────────────────────────────────────────────

// ActiveCrisis re-exported from shared/megastructureTypes

export interface MegastructureProject {
  id: MegastructureId;
  /** Index of currently active stage (0-based), null if idle or complete */
  activeStageIndex: number | null;
  /** Tick progress accumulated for the active stage */
  stageProgress: number;
  /** Number of stages fully completed */
  completedStages: number;
  /** True when all stages are done */
  complete: boolean;
  /** Ticks since last active drain fired */
  drainAccumulator: number;
  /**
   * True if the last drain attempt couldn't be fully paid.
   * Construction stalls until the next drain interval succeeds.
   */
  drainStalled: boolean;
  /** Active crisis blocking construction, or null */
  activeCrisis: ActiveCrisis | null;
  /** Crisis ids already used on the current stage (prevents double-firing) */
  crisisFiredThisStage: boolean;
  /**
   * Crisis countdown: ticks remaining before stage is lost due to low progress.
   * Non-null when stageProgressPct < CRISIS_COUNTDOWN_THRESHOLD.
   */
  crisisCountdownTicksRemaining: number | null;
  /**
   * True once stage progress has risen above the crisis countdown threshold.
   * Prevents countdown from firing during initial construction ramp-up.
   */
  progressReachedThreshold: boolean;
}

export interface MegastructureState {
  projects: Map<MegastructureId, MegastructureProject>;
}

// SerializedMegastructureProject re-exported from shared/megastructureTypes

export interface SerializedMegastructureState {
  projects: SerializedMegastructureProject[];
}

export function createMegastructureState(): MegastructureState {
  return { projects: new Map() };
}

function getOrCreateProject(state: MegastructureState, id: MegastructureId): MegastructureProject {
  let proj = state.projects.get(id);
  if (!proj) {
    proj = {
      id,
      activeStageIndex: null,
      stageProgress: 0,
      completedStages: 0,
      complete: false,
      drainAccumulator: 0,
      drainStalled: false,
      activeCrisis: null,
      crisisFiredThisStage: false,
      crisisCountdownTicksRemaining: null,
      progressReachedThreshold: false,
    };
    state.projects.set(id, proj);
  }
  return proj;
}

// ── Operations ────────────────────────────────────────────────────────────────

export interface StartStageResult {
  ok: boolean;
  error?: string;
}

/**
 * Begin the next stage of a megastructure.
 * Deducts refined material costs immediately from refinedStorage.
 */
export function startMegastructureStage(
  state: MegastructureState,
  id: MegastructureId,
  stageIndex: number,
  refinedStorage: Record<string, number>,
  unlockedTechIds?: Set<string>,
): StartStageResult {
  const def = MEGASTRUCTURE_DEFS[id];
  if (!def) return { ok: false, error: 'Unknown megastructure' };

  const stageDef = def.stages[stageIndex];
  if (!stageDef) return { ok: false, error: 'Invalid stage index' };

  const proj = getOrCreateProject(state, id);

  if (proj.complete) return { ok: false, error: 'Megastructure already complete' };
  if (proj.activeStageIndex !== null) return { ok: false, error: 'Stage already in progress' };
  if (stageIndex !== proj.completedStages) {
    return { ok: false, error: `Stage ${stageIndex + 1} not yet available` };
  }

  // Check stage-specific tech gates
  if (def.stageTechGates && def.stageTechGates[stageIndex]) {
    const requiredTechs = def.stageTechGates[stageIndex];
    for (const techId of requiredTechs) {
      if (!unlockedTechIds || !unlockedTechIds.has(techId)) {
        return { ok: false, error: `Requires research: ${techId}` };
      }
    }
  }

  // Check prerequisite megastructure
  if (def.prerequisite) {
    const prereqProj = state.projects.get(def.prerequisite.id);
    const prereqMet =
      prereqProj !== undefined && prereqProj.completedStages >= def.prerequisite.minCompletedStages;
    if (!prereqMet) {
      return {
        ok: false,
        error: `Requires ${MEGASTRUCTURE_DEFS[def.prerequisite.id].name} fully complete`,
      };
    }
  }

  // Affordability check
  for (const [resource, qty] of Object.entries(stageDef.cost)) {
    if ((refinedStorage[resource] ?? 0) < (qty ?? 0)) {
      return { ok: false, error: `Insufficient ${resource} (need ${qty ?? 0})` };
    }
  }

  // Deduct costs
  for (const [resource, qty] of Object.entries(stageDef.cost)) {
    if (qty !== undefined) {
      refinedStorage[resource] = (refinedStorage[resource] ?? 0) - qty;
    }
  }

  proj.activeStageIndex = stageIndex;
  proj.stageProgress = 0;
  proj.drainAccumulator = 0;
  proj.drainStalled = false;
  proj.activeCrisis = null;
  proj.crisisFiredThisStage = false;
  proj.crisisCountdownTicksRemaining = null;
  proj.progressReachedThreshold = false;
  return { ok: true };
}

/**
 * Resolve an active crisis by paying the resolution cost.
 * Clears the crisis and allows construction to resume.
 */
export function resolveCrisis(
  state: MegastructureState,
  id: MegastructureId,
  refinedStorage: Record<string, number>,
): StartStageResult {
  const proj = state.projects.get(id);
  if (!proj || !proj.activeCrisis) return { ok: false, error: 'No active crisis' };

  const crisisDef = CRISIS_DEFS[proj.activeCrisis.crisisId];
  if (!crisisDef) return { ok: false, error: 'Unknown crisis type' };

  for (const [resource, qty] of Object.entries(crisisDef.resolutionCost)) {
    if ((refinedStorage[resource] ?? 0) < (qty ?? 0)) {
      return { ok: false, error: `Insufficient ${resource} (need ${qty ?? 0})` };
    }
  }

  for (const [resource, qty] of Object.entries(crisisDef.resolutionCost)) {
    if (qty !== undefined) {
      refinedStorage[resource] = (refinedStorage[resource] ?? 0) - qty;
    }
  }

  if (crisisDef.pauseWindowTicks && crisisDef.pauseWindowTicks > 0) {
    // Two-phase resolution: materials paid, mandatory repair window begins
    proj.activeCrisis = {
      crisisId: proj.activeCrisis.crisisId,
      pending: false,
      pauseTicksRemaining: crisisDef.pauseWindowTicks,
    };
  } else {
    proj.activeCrisis = null;
  }
  return { ok: true };
}

/**
 * Skip an active crisis by sacrificing a portion of stage progress.
 * Progress is reduced by crisisDef.progressPenalty * baseTicks.
 */
export function skipCrisis(state: MegastructureState, id: MegastructureId): void {
  const proj = state.projects.get(id);
  if (!proj || !proj.activeCrisis || proj.activeStageIndex === null) return;

  const crisisDef = CRISIS_DEFS[proj.activeCrisis.crisisId];
  if (!crisisDef) return;

  const def = MEGASTRUCTURE_DEFS[id];
  const stageDef = def?.stages[proj.activeStageIndex];
  if (!stageDef) return;

  const penalty = crisisDef.progressPenalty * stageDef.baseTicks;
  proj.stageProgress = Math.max(0, proj.stageProgress - penalty);
  proj.activeCrisis = null;
}

// ── Crisis countdown constants ────────────────────────────────────────────────

/** Stage progress fraction below which the crisis countdown starts */
export const CRISIS_COUNTDOWN_THRESHOLD = 0.15;
/** Ticks the player has to recover before stage is lost */
export const CRISIS_COUNTDOWN_TICKS = 15;
/** Ticks remaining at which a near-end ARIA warning fires */
export const CRISIS_COUNTDOWN_WARNING_TICKS = 5;

// ── Tick ──────────────────────────────────────────────────────────────────────

export interface MegastructureTickResult {
  stageCompleted: { id: MegastructureId; stageIndex: number; bonus: MegastructureBonus } | null;
  winCondition: boolean;
  /** Crisis events that fired this tick (one per project max) */
  crisisTriggered: Array<{ id: MegastructureId; crisis: CrisisDef }>;
  /** Projects whose active drain stalled this tick (couldn't pay) */
  drainStalled: MegastructureId[];
  /** Projects whose drain stall cleared this tick (drain succeeded after being stalled) */
  drainUnstalled: MegastructureId[];
  /** Projects where the crisis countdown just started this tick */
  countdownStarted: Array<{ id: MegastructureId; stageName: string; ticksRemaining: number }>;
  /** Projects where the countdown hit the near-end warning threshold */
  countdownNearEnd: Array<{ id: MegastructureId; stageName: string; ticksRemaining: number }>;
  /** Projects that lost their stage because the countdown expired */
  stageLost: Array<{ id: MegastructureId; stageName: string; lostStageIndex: number }>;
}

/**
 * Advance construction progress for all active megastructure projects.
 * Progress rate = min(2, engineerCount / engineersRequired) per tick.
 * Stalls completely when engineerCount = 0 OR activeCrisis is set OR drainStalled is true.
 *
 * @param rng - optional random function for testing (defaults to Math.random)
 */
export function tickMegastructures(
  state: MegastructureState,
  engineerCount: number,
  refinedStorage?: Record<string, number>,
  rng: () => number = Math.random,
): MegastructureTickResult {
  const result: MegastructureTickResult = {
    stageCompleted: null,
    winCondition: false,
    crisisTriggered: [],
    drainStalled: [],
    drainUnstalled: [],
    countdownStarted: [],
    countdownNearEnd: [],
    stageLost: [],
  };

  for (const proj of state.projects.values()) {
    if (proj.activeStageIndex === null || proj.complete) continue;

    const def = MEGASTRUCTURE_DEFS[proj.id];
    const stageDef = def.stages[proj.activeStageIndex];
    if (!stageDef) continue;

    // ── Active drain ──────────────────────────────────────────────────────────
    if (stageDef.activeDrain && refinedStorage) {
      const drainInterval = stageDef.drainIntervalTicks ?? 3600;
      proj.drainAccumulator++;

      if (proj.drainAccumulator >= drainInterval) {
        proj.drainAccumulator = 0;

        // Check affordability
        let canPay = true;
        for (const [res, qty] of Object.entries(stageDef.activeDrain)) {
          if ((refinedStorage[res] ?? 0) < (qty ?? 0)) {
            canPay = false;
            break;
          }
        }

        if (canPay) {
          for (const [res, qty] of Object.entries(stageDef.activeDrain)) {
            if (qty !== undefined) refinedStorage[res] = (refinedStorage[res] ?? 0) - qty;
          }
          if (proj.drainStalled) {
            proj.drainStalled = false;
            result.drainUnstalled.push(proj.id);
          }
        } else {
          proj.drainStalled = true;
          result.drainStalled.push(proj.id);
        }
      }
    }

    // ── Repair pause countdown ────────────────────────────────────────────────
    if (proj.activeCrisis !== null && !proj.activeCrisis.pending) {
      // Materials paid; counting down mandatory repair window
      const remaining = proj.activeCrisis.pauseTicksRemaining ?? 0;
      if (remaining <= 1) {
        proj.activeCrisis = null; // repair complete, construction can resume
      } else {
        proj.activeCrisis.pauseTicksRemaining = remaining - 1;
      }
    }

    // ── Stall conditions ──────────────────────────────────────────────────────
    if (engineerCount === 0) continue;
    if (proj.activeCrisis !== null) continue;
    if (proj.drainStalled) continue;

    // ── Crisis check ──────────────────────────────────────────────────────────
    if (
      stageDef.crisisType &&
      !proj.crisisFiredThisStage &&
      proj.stageProgress > 0 // don't fire at tick 0
    ) {
      const prob = stageDef.crisisProbability ?? 0.00003;
      if (rng() < prob) {
        const crisisDef = CRISIS_DEFS[stageDef.crisisType];
        if (crisisDef) {
          proj.activeCrisis = { crisisId: stageDef.crisisType, pending: true };
          proj.crisisFiredThisStage = true;
          result.crisisTriggered.push({ id: proj.id, crisis: crisisDef });
          continue; // stall this tick (crisis just fired)
        }
      }
    }

    // ── Advance progress ──────────────────────────────────────────────────────
    const progressRate = Math.min(engineerCount / stageDef.engineersRequired, 2);
    proj.stageProgress += progressRate;

    if (proj.stageProgress >= stageDef.baseTicks) {
      const completedIndex = proj.activeStageIndex;
      proj.completedStages++;
      proj.activeStageIndex = null;
      proj.stageProgress = 0;
      proj.drainAccumulator = 0;
      proj.drainStalled = false;
      proj.activeCrisis = null;
      proj.crisisFiredThisStage = false;
      proj.crisisCountdownTicksRemaining = null;
      proj.progressReachedThreshold = false;

      if (stageDef.bonus.type === 'win_condition') {
        proj.complete = true;
        result.winCondition = true;
      }

      result.stageCompleted = { id: proj.id, stageIndex: completedIndex, bonus: stageDef.bonus };
      continue;
    }

    // ── Crisis countdown (stage loss on sustained low progress) ──────────────
    const stageProgressPct = proj.stageProgress / stageDef.baseTicks;

    // Track when progress first reaches the threshold (prevents countdown during initial ramp)
    if (!proj.progressReachedThreshold && stageProgressPct >= CRISIS_COUNTDOWN_THRESHOLD) {
      proj.progressReachedThreshold = true;
    }

    if (proj.progressReachedThreshold && stageProgressPct > 0 && stageProgressPct < CRISIS_COUNTDOWN_THRESHOLD) {
      if (proj.crisisCountdownTicksRemaining === null) {
        // Start countdown
        proj.crisisCountdownTicksRemaining = CRISIS_COUNTDOWN_TICKS;
        result.countdownStarted.push({
          id: proj.id,
          stageName: stageDef.name,
          ticksRemaining: CRISIS_COUNTDOWN_TICKS,
        });
      } else {
        proj.crisisCountdownTicksRemaining--;
        if (proj.crisisCountdownTicksRemaining === CRISIS_COUNTDOWN_WARNING_TICKS) {
          result.countdownNearEnd.push({
            id: proj.id,
            stageName: stageDef.name,
            ticksRemaining: CRISIS_COUNTDOWN_WARNING_TICKS,
          });
        }
        if (proj.crisisCountdownTicksRemaining <= 0) {
          // Stage lost — drop back to previous stage
          const lostIndex = proj.activeStageIndex;
          result.stageLost.push({
            id: proj.id,
            stageName: stageDef.name,
            lostStageIndex: lostIndex,
          });
          proj.activeStageIndex = null;
          proj.stageProgress = 0;
          proj.drainAccumulator = 0;
          proj.drainStalled = false;
          proj.activeCrisis = null;
          proj.crisisFiredThisStage = false;
          proj.crisisCountdownTicksRemaining = null;
          proj.progressReachedThreshold = false;
        }
      }
    } else {
      // Progress recovered above threshold — cancel countdown
      proj.crisisCountdownTicksRemaining = null;
    }
  }

  return result;
}

// ── Snapshot / Serialization ──────────────────────────────────────────────────

// MegastructureProjectSnapshot re-exported from shared/megastructureTypes

export function snapshotProject(
  proj: MegastructureProject,
  engineerCount: number,
): MegastructureProjectSnapshot {
  let stageProgressPct = 0;
  let estimatedTicksRemaining: number | null = null;
  let hasDrain = false;
  let activeStageDrain: Partial<Record<string, number>> | null = null;
  let drainIntervalTicks: number | null = null;

  if (proj.activeStageIndex !== null) {
    const def = MEGASTRUCTURE_DEFS[proj.id];
    const stageDef = def?.stages[proj.activeStageIndex];
    if (stageDef) {
      stageProgressPct = proj.stageProgress / stageDef.baseTicks;

      const isStalled = engineerCount === 0 || proj.activeCrisis !== null || proj.drainStalled;
      const progressRate = isStalled ? 0 : Math.min(engineerCount / stageDef.engineersRequired, 2);

      if (progressRate > 0) {
        estimatedTicksRemaining = Math.ceil(
          (stageDef.baseTicks - proj.stageProgress) / progressRate,
        );
      }

      if (stageDef.activeDrain) {
        hasDrain = true;
        activeStageDrain = stageDef.activeDrain;
        drainIntervalTicks = stageDef.drainIntervalTicks ?? 3600;
      }
    }
  }

  return {
    id: proj.id,
    activeStageIndex: proj.activeStageIndex,
    stageProgress: proj.stageProgress,
    stageProgressPct,
    completedStages: proj.completedStages,
    complete: proj.complete,
    estimatedTicksRemaining,
    drainAccumulator: proj.drainAccumulator,
    drainStalled: proj.drainStalled,
    activeCrisis: proj.activeCrisis,
    crisisFiredThisStage: proj.crisisFiredThisStage,
    crisisCountdownTicksRemaining: proj.crisisCountdownTicksRemaining,
    hasDrain,
    activeStageDrain,
    drainIntervalTicks,
  };
}

export function serializeMegastructureState(
  state: MegastructureState,
): SerializedMegastructureState {
  return {
    projects: Array.from(state.projects.values()).map((p) => ({
      id: p.id,
      activeStageIndex: p.activeStageIndex,
      stageProgress: p.stageProgress,
      completedStages: p.completedStages,
      complete: p.complete,
      drainAccumulator: p.drainAccumulator,
      drainStalled: p.drainStalled,
      activeCrisis: p.activeCrisis,
      crisisFiredThisStage: p.crisisFiredThisStage,
      crisisCountdownTicksRemaining: p.crisisCountdownTicksRemaining,
      progressReachedThreshold: p.progressReachedThreshold,
    })),
  };
}

export function deserializeMegastructureState(
  data: SerializedMegastructureState,
): MegastructureState {
  const state = createMegastructureState();
  for (const p of data.projects) {
    state.projects.set(p.id, {
      id: p.id,
      activeStageIndex: p.activeStageIndex,
      stageProgress: p.stageProgress,
      completedStages: p.completedStages,
      complete: p.complete,
      drainAccumulator: p.drainAccumulator ?? 0,
      drainStalled: p.drainStalled ?? false,
      activeCrisis: p.activeCrisis ?? null,
      crisisFiredThisStage: p.crisisFiredThisStage ?? false,
      crisisCountdownTicksRemaining: p.crisisCountdownTicksRemaining ?? null,
      progressReachedThreshold: p.progressReachedThreshold ?? false,
    });
  }
  return state;
}
